SELECT (SELECT COUNT(*) FROM `user` WHERE is_service_account = false) AS users,(SELECT COUNT(*) FROM `data_source`) AS datasources,(SELECT COUNT(*) FROM `star`) AS stars,(SELECT COUNT(*) FROM `playlist`) AS playlists,(SELECT COUNT(*) FROM `alert`) AS alerts,(SELECT COUNT(*) FROM `correlation`) AS correlations,(SELECT COUNT(*) FROM `user` WHERE is_service_account = false AND last_seen_at > ?) AS active_users,(SELECT COUNT(*) FROM `user` WHERE is_service_account = false AND last_seen_at > ?) AS daily_active_users,(SELECT COUNT(*) FROM `user` WHERE is_service_account = false AND last_seen_at > ?) AS monthly_active_users,(SELECT COUNT(id) FROM `dashboard_provisioning`) AS provisioned_dashboards,(SELECT COUNT(id) FROM `dashboard_snapshot`) AS snapshots,(SELECT COUNT(id) FROM `dashboard_version`) AS dashboard_versions,(SELECT COUNT(id) FROM `annotation`) AS annotations,(SELECT COUNT(id) FROM `team`) AS teams,(SELECT COUNT(id) FROM `user_auth_token`) AS auth_tokens,(SELECT COUNT(id) FROM `alert_rule`) AS alert_rules,(SELECT COUNT(id) FROM `api_key`WHERE service_account_id IS NULL) AS api_keys,(SELECT COUNT(id) FROM `library_element` WHERE kind = ?) AS library_panels,(SELECT COUNT(*) FROM `data_keys`) AS data_keys,(SELECT COUNT(*) FROM `data_keys`WHERE active = true) AS active_data_keys,(SELECT COUNT(*) FROM `dashboard_public`) AS public_dashboards,(SELECT MIN(timestamp) FROM `migration_log`) AS database_created_time,(SELECT COUNT(DISTINCT (`rule_group`)) FROM `alert_rule`) AS rule_groups,1 AS admins, 0 AS editors, 0 AS viewers, 1 AS active_admins, 0 AS active_editors, 0 AS active_viewers, 0 AS daily_active_admins, 0 AS daily_active_editors, 0 AS daily_active_viewers
